{
  "name": "scrape_page",
  "description": "Open a page in a browser and extract structured data from rendered content.",
  "input_schema": {
    "type": "object",
    "properties": {
      "url": { "type": "string" },
      "goal": { "type": "string" },
      "fields": {
        "type": "array",
        "items": { "type": "string" }
      }
    },
    "required": ["url", "goal"]
  },
  "strict": true
}

{
  "url": "https://example.com/products",
  "items": [
    { "title": "Product A", "price": "$19.99" },
    { "title": "Product B", "price": "$24.99" }
  ],
  "notes": ["Page required JavaScript rendering"]
}
